  function apply() {
    if (!shouldZh()) return;
    var root = document.getElementById("p0-crypto-rail");
    if (!root) return;
    root.querySelectorAll("h2,h3,p,span").forEach(function (el) {
      var text = el.textContent.trim();
      if (map[text]) el.textContent = map[text];
    });
  }

  function runSoon() {
    apply();
    setTimeout(apply, 80);
    setTimeout(apply, 250);
  }

  if (document.readyState === "loading") document.addEventListener("DOMContentLoaded", runSoon);
  else runSoon();
